sql:
SELECT AVG(demand) AS average_demand
FROM water_supply_data
WHERE region_id = 1;

SELECT region_id, AVG(demand) AS avg_water_demand
FROM water_supply_data
GROUP BY region_id;

SELECT year_month, water_quality_index
FROM water_supply_data
ORDER BY year_month ASC;

SELECT DISTINCT region_id
FROM water_supply_data
ORDER BY region_id;

SELECT year_month, connections, demand, consumption
FROM water_supply_data
ORDER BY year_month ASC;

SELECT year_month, demand
FROM water_supply_data
ORDER BY year_month ASC;

SELECT DISTINCT r.region_name
FROM water_supply_data wsd
JOIN regions r ON wsd.region_id = r.region_id;

external_knowledge:
Above-average water demand refers to regions where the average demand is greater than the overall average demand across all regions; 
A leakage rate of 10% means that 10% of the total water supply is lost due to leaks; 
The maintenance status 'needs repair' indicates that the region's water infrastructure requires maintenance.
